前台工作人员Ariel很热情，快速办理好入住手续并升级到粤韵套房。花园酒店，从1985到现在一直在线，好吃好逛好住你值得拥有～', '2023-09-02', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g12000c1zrne2501B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000c1zqlkyE662_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000c1zp4o23368_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000c1zm42vC2BA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000c1zpn8s3F13_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂非常气派，有很多鲜花和表演，实属于五星级', '酒店大堂非常气派，有很多鲜花和表演，实属于五星级
